const deals = [];
for (let i = 0; i < 5; i++) {
  deals.push({
    id: Date.now() + i,
    title: `USB-C Fast Charger ${i + 1}`,
    originalPrice: 29.99 + (i * 5),
    currentPrice: 19.99 + (i * 3),
    salePrice: 19.99 + (i * 3),
    discount: 30 + (i * 2),
    store: 'Amazon',
    category: 'Chargers',
    imageUrl: 'https://images.unsplash.com/photo-1609592806596-4d8b5b3c8f5e?w=400',
    image: 'https://images.unsplash.com/photo-1609592806596-4d8b5b3c8f5e?w=400',
    link: 'https://amazon.com/product-' + i,
    affiliateLink: 'https://amazon.com/product-' + i,
    rating: 4.2 + (i * 0.1),
    couponCode: i % 2 === 0 ? 'SAVE' + (30 + i * 2) : null,
    expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
  });
}
return deals.map(deal => ({ json: deal }));
